fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let mut sorted = nums.clone();
    sorted.sort();

    if nums == sorted {
        return 0;
    }

    let mut k = 0;
    let mut mask = 1 << 30; // Start with a large bit mask (since i64 can be up to 2^63 -1)

    while mask > 0 {
        let candidate = k | mask;
        let mut possible = true;

        for i in 0..n {
            let num = nums[i] as usize;
            let target = sorted[i] as usize;
            if num != target && ((num & target) & candidate) != candidate {
                possible = false;
                break;
            }
        }

        if possible {
            k = candidate;
        }
        mask >>= 1;
    }

    k
}
